// Validar firma HMAC de Mercado Pago
// Documentación: https://www.mercadopago.com.ar/developers/es/docs/your-integrations/notifications/webhooks
const crypto = require('crypto');

const secret     = $env.MP_WEBHOOK_SECRET;
const xSignature = $json.headers['x-signature'] || '';
const xRequestId = $json.headers['x-request-id'] || '';
const dataId     = $json.body?.data?.id || '';

// Extraer ts y v1 del header x-signature
const ts = xSignature.match(/ts=(\d+)/)?.[1];
const v1 = xSignature.match(/v1=([a-f0-9]+)/)?.[1];

if (!ts || !v1) {
  throw new Error('Header x-signature ausente o malformado — webhook rechazado');
}

// Construir el manifest según la documentación de MP
const manifest = `id:${dataId};request-id:${xRequestId};ts:${ts};`;

// Calcular HMAC SHA256
const hash = crypto
  .createHmac('sha256', secret)
  .update(manifest)
  .digest('hex');

if (hash !== v1) {
  throw new Error(`Firma inválida — posible ataque. hash=${hash} v1=${v1}`);
}

// Firma válida — pasar el body al siguiente nodo
return [{ json: $json }];

const sub = $input.first().json;

// external_reference es el user_id de Supabase
// Se configura al crear la suscripción desde Next.js
const user_id = sub.external_reference;

// Mapear el status de MP al status de Fluir
const STATUS_MAP = {
  'authorized':  'active',
  'pending':     'trialing',
  'paused':      'paused',
  'cancelled':   'cancelled',
  'ended':       'cancelled',
};

const mp_status    = sub.status;
const fluir_status = STATUS_MAP[mp_status] || 'cancelled';

// Determinar el plan según el precio
// Los precios se configuran al crear los planes en MP
const amount = sub.auto_recurring?.transaction_amount || 0;
let plan = 'free';
if (amount >= 8000) plan = 'gold';
else if (amount >= 3500) plan = 'plus';

// Si se canceló → volver a free
if (fluir_status === 'cancelled') plan = 'free';

return [{
  json: {
    user_id,
    plan,
    fluir_status,
    mp_status,
    mp_subscription_id:     sub.id,
    mp_amount:              amount,
    current_period_end:     sub.next_payment_date || null,
    updated_at:             new Date().toISOString()
  }
}];

