const payment = $input.first().json;

// Si el cobro fue rechazado, pausamos el plan
const PAYMENT_STATUS = {
  'approved':       'ok',
  'pending':        'pending',
  'rejected':       'rejected',
  'cancelled':      'cancelled',
  'refunded':       'refunded',
  'charged_back':   'charged_back'
};

const status = PAYMENT_STATUS[payment.status] || 'unknown';

return [{
  json: {
    payment_id:     payment.id,
    status,
    amount:         payment.transaction_amount,
    user_id:        payment.external_reference,
    should_pause:   status === 'rejected',
    updated_at:     new Date().toISOString()
  }
}];
